svg.script:
(function() {
  const cursor = document.getElementById('cursor');
  const overlay = document.getElementById('overlay');

  const steps = [
    {x: 330,  y: 223,  wait: 3.32, click: false, img: "Imgs/Main.png"},
    {x: 648,  y: 312,  wait: 2.22, click: false, img: "Imgs/Main.png"},
    {x: 648,  y: 312,  wait: 0.03, click: true,  img: "Imgs/2nd.png"},
    {x: 658,  y: 323,  wait: 0.22, click: true,  img: "Imgs/26th.png"},
    {x: 330,  y: 223,  wait: 0.32, click: false, img: "Imgs/Main.png"}
  ];

  function moveSmooth(x, y) {
    cursor.style.transition = "transform 1.8s cubic-bezier(0.22,1,0.36,1)";
    cursor.setAttribute("transform", `translate(${x-11.5},${y-11.5})`);
  }

  async function clickEffect(x, y) {
    cursor.style.transition = "transform 0.14s ease";
    cursor.setAttribute("transform", `translate(${x-11.5},${y-11.5}) scale(0.6)`);
    await new Promise(r => setTimeout(r, 120));
    cursor.style.transition = "transform 0.4s ease-out";
    cursor.setAttribute("transform", `translate(${x-11.5},${y-11.5}) scale(1)`);
  }

  async function playSequence() {
    while (true) {
      for (const step of steps) {
        overlay.setAttributeNS("http://www.w3.org/1999/xlink", "href", step.img);

        const cx = step.x;
        const cy = step.y;

        if (step.click) {
          await clickEffect(cx, cy);
        } else {
          moveSmooth(cx, cy);
        }

        await new Promise(r => setTimeout(r, step.wait * 1000));
      }
    }
  }

  // Start the animation
  playSequence();
})();
